.mrg-date-field {
  color: var(--mrg-semantic-color-foreground-primary);
  display: grid;
  font-family: var(--mrg-semantic-font-family-prose);
  gap: var(--mrg-semantic-space-stack-xs);
  inline-size: 100%;
  min-inline-size: 0;
}

.mrg-date-field-control {
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-strong) solid var(--mrg-semantic-color-border-interactive);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: inherit;
  font: inherit;
  inline-size: 100%;
  min-block-size: var(--mrg-semantic-density-control-height);
  min-inline-size: 0;
  padding: var(--mrg-semantic-density-control-padding-block)
    var(--mrg-semantic-density-control-padding-inline);
}

.mrg-date-field-control:focus-visible {
  box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
    var(--mrg-semantic-color-focus-contrast-background);
  outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
  outline-offset: var(--mrg-semantic-focus-offset);
}

.mrg-date-field-control:invalid {
  border-color: var(--mrg-semantic-color-status-danger-border);
}

.mrg-date-field-control:disabled {
  background: var(--mrg-semantic-color-background-disabled);
  border-color: var(--mrg-semantic-color-border-disabled);
  color: var(--mrg-semantic-color-foreground-disabled);
}

.mrg-date-field [data-slot="date-field-context"] {
  border-inline-start: var(--mrg-semantic-border-width-emphasis) solid
    var(--mrg-semantic-color-brand-living);
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
  line-height: var(--mrg-semantic-font-line-height-body);
  overflow-wrap: anywhere;
  padding-inline-start: var(--mrg-semantic-space-inline-sm);
}

@media (pointer: coarse) {
  .mrg-date-field-control {
    min-block-size: var(--mrg-semantic-size-target-preferred);
  }
}

@media (forced-colors: active) {
  .mrg-date-field-control {
    background: Field;
    border-color: FieldText;
    color: FieldText;
  }

  .mrg-date-field-control:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }

  .mrg-date-field [data-slot="date-field-context"] {
    border-color: Highlight;
    color: CanvasText;
  }
}

"use client";

import { forwardRef, useId, useMemo, type InputHTMLAttributes, type ReactNode } from "react";

import {
  formatCanonicalDate,
  mergeTemporalRefs,
  nativeTemporalInputProps,
  useNativeTemporalControl,
} from "./date-time-utils";
import "./date-field.css";

export interface DateFieldProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  "defaultValue" | "onChange" | "type" | "value"
> {
  /** Initial canonical `YYYY-MM-DD` value for uncontrolled use and native form reset. */
  readonly defaultValue?: string;
  /** Locale used by the built-in long-form date context formatter. */
  readonly locale?: string;
  /** Receives the original native date-input change event after internal state is updated. */
  readonly onChange?: InputHTMLAttributes<HTMLInputElement>["onChange"];
  /** Reports canonical date edits and native form-reset restoration. */
  readonly onValueChange?: (value: string) => void;
  /** Adds an aria-described date context; `false` removes its UI and accessibility output. */
  readonly showDateContext?: boolean;
  /** Custom date context content or renderer, falling back to locale-formatted context when omitted. */
  readonly dateContext?: ReactNode | ((canonicalValue: string) => ReactNode);
  /** Controlled canonical `YYYY-MM-DD` value; pair with `onValueChange`. */
  readonly value?: string;
}

function hasContent(value: ReactNode): boolean {
  return value !== null && value !== undefined && value !== false && value !== "";
}

export const DateField = forwardRef<HTMLInputElement, DateFieldProps>(function DateField(
  {
    "aria-describedby": ariaDescribedBy,
    className,
    dateContext,
    defaultValue = "",
    locale = "en-US",
    onChange,
    onValueChange,
    showDateContext = false,
    value,
    ...nativeProps
  },
  forwardedRef,
) {
  const generatedId = useId().replaceAll(":", "");
  const control = useNativeTemporalControl({ defaultValue, onChange, onValueChange, value });
  const context = useMemo(() => {
    if (!showDateContext || control.value === "") return null;
    if (typeof dateContext === "function") return dateContext(control.value);
    if (hasContent(dateContext)) return dateContext;
    return formatCanonicalDate(control.value, locale);
  }, [control.value, dateContext, locale, showDateContext]);
  const contextId = context === null ? undefined : `mrg-date-field-${generatedId}-context`;

  return (
    <span className="mrg-date-field" data-context={contextId === undefined ? undefined : true}>
      <input
        {...nativeTemporalInputProps("date")}
        {...nativeProps}
        aria-describedby={[ariaDescribedBy, contextId].filter(Boolean).join(" ") || undefined}
        className={
          className === undefined ? "mrg-date-field-control" : `mrg-date-field-control ${className}`
        }
        data-slot="date-field"
        onChange={control.onChange}
        ref={mergeTemporalRefs(control.inputRef, forwardedRef)}
        type="date"
        value={control.value}
      />
      {contextId === undefined ? null : (
        <span data-slot="date-field-context" id={contextId}>
          {context}
        </span>
      )}
    </span>
  );
});

DateField.displayName = "DateField";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type ChangeEvent,
  type InputHTMLAttributes,
  type Ref,
} from "react";

export type TemporalInputType = "date" | "datetime-local" | "month" | "time";

export interface NativeTemporalControlOptions {
  readonly defaultValue?: string | undefined;
  readonly onChange?: ((event: ChangeEvent<HTMLInputElement>) => void) | undefined;
  readonly onValueChange?: ((value: string) => void) | undefined;
  readonly value?: string | undefined;
}

export interface NativeTemporalControlResult {
  readonly inputRef: (node: HTMLInputElement | null) => void;
  readonly onChange: (event: ChangeEvent<HTMLInputElement>) => void;
  readonly setValue: (value: string) => void;
  readonly value: string;
}

export function mergeTemporalRefs<T>(
  ...refs: readonly (Ref<T> | undefined)[]
): (node: T | null) => void {
  return (node) => {
    for (const ref of refs) {
      if (typeof ref === "function") ref(node);
      else if (ref !== null && ref !== undefined) {
        (ref as { current: T | null }).current = node;
      }
    }
  };
}

export function useNativeTemporalControl({
  defaultValue = "",
  onChange,
  onValueChange,
  value,
}: NativeTemporalControlOptions): NativeTemporalControlResult {
  const controlled = value !== undefined;
  const [uncontrolledValue, setUncontrolledValue] = useState(defaultValue);
  const input = useRef<HTMLInputElement | null>(null);
  const resolvedValue = controlled ? value : uncontrolledValue;
  const latestValue = useRef(resolvedValue);
  latestValue.current = resolvedValue;

  useEffect(() => {
    const form = input.current?.form;
    if (form === null || form === undefined) return;
    let timer: ReturnType<typeof setTimeout> | undefined;
    const handleReset = (event: Event) => {
      timer = setTimeout(() => {
        if (event.defaultPrevented || latestValue.current === defaultValue) return;
        if (!controlled) setUncontrolledValue(defaultValue);
        onValueChange?.(defaultValue);
      }, 0);
    };
    form.addEventListener("reset", handleReset);
    return () => {
      form.removeEventListener("reset", handleReset);
      if (timer !== undefined) clearTimeout(timer);
    };
  }, [controlled, defaultValue, onValueChange]);

  const handleChange = useCallback(
    (event: ChangeEvent<HTMLInputElement>) => {
      if (!controlled) setUncontrolledValue(event.currentTarget.value);
      onChange?.(event);
      onValueChange?.(event.currentTarget.value);
    },
    [controlled, onChange, onValueChange],
  );

  const setValue = useCallback(
    (nextValue: string) => {
      if (latestValue.current === nextValue) return;
      if (!controlled) setUncontrolledValue(nextValue);
      onValueChange?.(nextValue);
    },
    [controlled, onValueChange],
  );

  return {
    inputRef: (node) => {
      input.current = node;
    },
    onChange: handleChange,
    setValue,
    value: resolvedValue,
  };
}

export function isCanonicalDate(value: string): boolean {
  const match = /^(\d{4})-(\d{2})-(\d{2})$/u.exec(value);
  if (match === null) return false;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const date = new Date(Date.UTC(year, month - 1, day));
  return (
    date.getUTCFullYear() === year && date.getUTCMonth() === month - 1 && date.getUTCDate() === day
  );
}

export function canonicalDate(year: number, month: number, day: number): string {
  return `${String(year).padStart(4, "0")}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
}

export function parseCanonicalDate(value: string): Date | null {
  if (!isCanonicalDate(value)) return null;
  const [year, month, day] = value.split("-").map(Number) as [number, number, number];
  return new Date(Date.UTC(year, month - 1, day));
}

export function daysInMonth(year: number, month: number): number {
  return new Date(Date.UTC(year, month, 0)).getUTCDate();
}

export function addCalendarDays(value: string, amount: number): string {
  const date = parseCanonicalDate(value);
  if (date === null || !Number.isSafeInteger(amount)) return value;
  date.setUTCDate(date.getUTCDate() + amount);
  return canonicalDate(date.getUTCFullYear(), date.getUTCMonth() + 1, date.getUTCDate());
}

export function addCalendarMonths(value: string, amount: number): string {
  const date = parseCanonicalDate(value);
  if (date === null || !Number.isSafeInteger(amount)) return value;
  const day = date.getUTCDate();
  date.setUTCDate(1);
  date.setUTCMonth(date.getUTCMonth() + amount);
  date.setUTCDate(Math.min(day, daysInMonth(date.getUTCFullYear(), date.getUTCMonth() + 1)));
  return canonicalDate(date.getUTCFullYear(), date.getUTCMonth() + 1, date.getUTCDate());
}

export function inclusiveCalendarDays(start: string, end: string): number | null {
  const startDate = parseCanonicalDate(start);
  const endDate = parseCanonicalDate(end);
  if (startDate === null || endDate === null || endDate < startDate) return null;
  return Math.round((endDate.getTime() - startDate.getTime()) / 86_400_000) + 1;
}

export function formatCanonicalDate(
  value: string,
  locale: string,
  options: Intl.DateTimeFormatOptions = {
    day: "numeric",
    month: "long",
    weekday: "long",
    year: "numeric",
    timeZone: "UTC",
  },
): string | null {
  const date = parseCanonicalDate(value);
  return date === null ? null : new Intl.DateTimeFormat(locale, options).format(date);
}

export function nativeTemporalInputProps(
  type: TemporalInputType,
): Pick<InputHTMLAttributes<HTMLInputElement>, "inputMode"> {
  return type === "time" ? { inputMode: "numeric" } : {};
}
